-- Carga inicial de establecimientos desde el prototipo DGIE
on conflict (id) do update set
  zona=excluded.zona,
  nombre=excluded.nombre,
  cue=excluded.cue,
  direccion=excluded.direccion,
  barrio=excluded.barrio,
  nivel=excluded.nivel,
  tipo=excluded.tipo,
  estado=excluded.estado,
  updated_at=now();
